INSERT INTO ai_resume_parse (id, resume_id, user_id, raw_text, parsed_result, skills, experience, education, name, phone, email, parse_status, is_manual_modified, created_at, updated_at) VALUES (4, NULL, '088e8a07-e365-4955-99f2-894c77fcd5d4', '求职简历（测试用） 姓名：张三 性别：男 年龄：22岁 联系电话：13800138000 电子邮箱：zhangsan@test.com 求职意向：软件工程师（后端/前端） 期望薪资：8000-10000元/月 期望城市：北京、上海、广州 一、教育背景 学校名称：XX大学 专业：计算机科学与技术（本科） 就读时间：2020年9月 - 2024年6月 学业成绩：GPA 3.7/4.0（专业前15%） 核心课程：计算机组成原理、数据结构、Java编程、Python开发、Web前端技术、数据库原理、操作系统 二、专业技能 编程语言：熟练掌握Python、Java、JavaScript，了解C++，能独立完成项目开发 前端技术：掌握Vue3、Element Plus、Vite、Axios，能开发响应式页面，熟悉前端工程化 后端技术：熟悉FastAPI、SpringBoot框架，掌握RESTful接口开发，了解微服务思想 数据库：熟练使用MySQL、达梦数据库（DM8），能编写复杂SQL语句，了解数据库优化 其他技能：掌握Git版本控制、Docker容器基础，了解国产化系统（银河麒麟）适配，具备良好的代码规范和问题排查能力 三、项目经历 项目名称：基于AI的人才职位智能匹配系统 项目时间：2023年9月 - 2024年3月 担任角色：前端开发工程师 项目描述：该项目为软件杯竞赛项目，基于Vue3+FastAPI+达梦数据库开发，适配LoongArch 3A5000+银河麒麟国产化系统，实现求职者简历上传、企业岗位发布、AI智能匹配、能力图谱可视化等功能，解决人才与岗位精准匹配的痛点。 负责内容： 负责前端页面开发，包括登录页、简历上传页、岗位匹配页、能力图谱页，使用Element Plus组件库实现页面美化和交互 封装前端API请求，配置跨域代理，实现前后端数据交互，确保简历上传、匹配结果展示等功能正常运行 参与项目国产化适配，优化页面兼容性，确保系统在银河麒麟系统上正常显示和使用 配合后端开发人员完成接口联调，排查并解决前端语法错误、数据渲染异常等问题 项目成果：项目成功完成并参与软件杯竞赛，获得校级二等奖，实现简历解析准确率90%以上，岗位匹配响应时间≤1秒，支持单账号多角色（求职者/企业）切换使用。 四、实习经历 公司名称：XX科技有限公司 实习岗位：前端开发实习生 实习时间：2024年1月 - 2024年4月 实习内容： 协助开发公司内部管理系统前端页面，使用Vue3+Element Plus实现表单提交、数据展示等功能 参与前端代码优化，修复页面兼容性问题，提升页面加载速度和用户体验 配合测试人员完成功能测试，修改前端bug，确保系统稳定运行 五、荣誉奖项 2023年11月：软件杯全国大学生软件设计大赛 校级二等奖 2022年12月：XX大学 三好学生标兵 2022年6月：全国计算机二级证书（Python语言） 2021年12月：XX大学 优秀学生奖学金 六、自我评价 具备扎实的计算机专业基础，熟练掌握前后端开发技术和国产化系统适配相关知识，参与过软件杯竞赛项目和企业实习，具备较强的项目开发能力和问题排查能力。工作认真负责，善于沟通协作，学习能力强，能快速适应新的技术和工作环境，对软件开发有浓厚的兴趣，致力于成为一名优秀的软件工程师，为企业发展贡献力量。', '{"name": "张三", "phone": "13800138000", "email": "zhangsan@test.com", "education": "本科", "experience_years": "未提供", "skills": ["Python", "Java", "JavaScript", "Vue3", "Element Plus", "Vite", "Axios", "FastAPI", "SpringBoot", "MySQL", "达梦数据库", "Git", "Docker", "银河麒麟"], "work_experience": [{"company": "XX科技有限公司", "position": "前端开发实习生", "duration": "2024年1月 - 2024年4月", "description": "协助开发公司内部管理系统前端页面，使用Vue3+Element Plus实现表单提交、数据展示等功能；参与前端代码优化，修复页面兼容性问题，提升页面加载速度和用户体验；配合测试人员完成功能测试，修改前端bug，确保系统稳定运行"}], "education_history": [{"school": "XX大学", "degree": "本科", "major": "计算机科学与技术", "duration": "2020年9月 - 2024年6月"}], "self_evaluation": "具备扎实的计算机专业基础，熟练掌握前后端开发技术和国产化系统适配相关知识，参与过软件杯竞赛项目和企业实习，具备较强的项目开发能力和问题排查能力。工作认真负责，善于沟通协作，学习能力强，能快速适应新的技术和工作环境，对软件开发有浓厚的兴趣，致力于成为一名优秀的软件工程师，为企业发展贡献力量。", "highlights": ["参与软件杯竞赛并获得校级二等奖", "掌握Vue3、FastAPI等技术栈", "熟悉国产化系统适配", "具备良好的代码规范和问题排查能力"]}', '["Python", "Java", "JavaScript", "Vue3", "Element Plus", "Vite", "Axios", "FastAPI", "SpringBoot", "MySQL", "达梦数据库", "Git", "Docker", "银河麒麟"]', '未提供', '本科', '张三', '13800138000', 'zhangsan@test.com', 'completed', 0, '2026-04-19 15:42:46.188196', '2026-04-19 15:42:46.188196');
