024年1月 - 2024年4月", "description": "协助开发公司内部管理系统前端页面，使用Vue3+Element Plus实现表单提交、数据展示等功能；参与前端代码优化，修复页面兼容性问题，提升页面加载速度和用户体验；配合测试人员完成功能测试，修改前端bug，确保系统稳定运行"}], "education_history": [{"school": "XX大学", "degree": "本科", "major": "计算机科学与技术", "duration": "2020年9月 - 2024年6月"}], "self_evaluation": "具备扎实的计算机专业基础，熟练掌握前后端开发技术和国产化系统适配相关知识，参与过软件杯竞赛项目和企业实习，具备较强的项目开发能力和问题排查能力。工作认真负责，善于沟通协作，学习能力强，能快速适应新的技术和工作环境，对软件开发有浓厚的兴趣，致力于成为一名优秀的软件工程师，为企业发展贡献力量。", "highlights": ["参与软件杯竞赛并获得校级二等奖", "掌握Vue3、FastAPI等技术栈", "熟悉国产化系统适配", "具备良好的代码规范和问题排查能力"]}', '["Python", "Java", "JavaScript", "Vue3", "Element Plus", "Vite", "Axios", "FastAPI", "SpringBoot", "MySQL", "达梦数据库", "Git", "Docker", "银河麒麟"]', '未提供', '本科', '张三', '13800138000', 'zhangsan@test.com', 'completed', 0, '2026-04-22 21:49:36.411821', '2026-04-22 21:49:36.411821');
INSERT INTO ai_job_parse (id, job_id, user_id, raw_text, parsed_result, required_skills, job_requirements, salary_range, job_title, parse_status, is_manual_modified, created_at, updated_at) VALUES (1, NULL, '088e8a07-e365-4955-99f2-894c77fcd5d4', '高级 Python 后端工程师 岗位说明书 一、基本信息 岗位名称：高级 Python 后端工程师 薪资范围：20K-30K・14 薪 工作地点：江苏省南京市建邺区 工作时间：朝九晚六周末双休，法定节假日正常休息 所属部门：技术研发部 岗位类型：全职 招聘人数：2 人 二、岗位描述 岗位职责 负责公司人才匹配系统后端架构设计与开发，基于 FastAPI 搭建高性能、高可用的 RESTful API； 参与系统核心模块（AI 解析、匹配算法、能力图谱）的开发与优化，解决高并发、大数据量场景下的性能问题； 与前端、算法团队协作，完成业务需求的全流程落地，保障产品迭代效率； 负责后端服务的部署、监控与维护，处理线上问题，保障系统稳定运行； 参与技术方案评审、代码 Review，推动团队技术规范落地。 岗位需求 熟练掌握 Python 语言，有扎实的语法基础，熟悉 FastAPI 框架开发； 熟悉 MySQL 数据库，能独立完成 SQL 编写、索引优化与性能调优； 了解 NLP 或大模型应用开发，有简历解析、文本匹配相关项目经验优先； 熟悉 Linux 开发环境，掌握 Git 版本控制工具； 有良好的问题排查能力、沟通能力和团队协作意识。 三、任职要求 学历要求：本科及以上学历，计算机相关专业优先 工作经验：3-5 年后端开发经验，有互联网或人力资源系统开发经验优先 技能要求（AI 提取）： Python / FastAPI MySQL / SQLAlchemy RESTful API 设计 大模型应用开发（如 Qwen、LLM 调用） Linux 环境开发 Git 版本控制 四、其他信息 福利待遇：五险一金、带薪年假、年度体检、节日福利、弹性工作制、定期技术分享会 工作氛围：扁平化管理，技术氛围浓厚，支持个人技术成长与创新实践 发展空间：可参与核心项目架构设计，有机会接触前沿 AI 技术与国产化适配方案', '{"job_title": "高级 Python 后端工程师", "salary_range": "20K-30K・14 薪", "location": "江苏省南京市建邺区", "job_type": "全职", "required_skills": ["Python", "FastAPI", "MySQL", "SQLAlchemy", "RESTful API", "大模型应用开发", "Linux", "Git"], "required_education": "本科及以上学历，计算机相关专业优先", "required_experience": "3-5 年后端开发经验，有互联网或人力资源系统开发经验优先", "job_responsibilities": ["负责公司人才匹配系统后端架构设计与开发，基于 FastAPI 搭建高性能、高可用的 RESTful API", "参与系统核心模块（AI 解析、匹配算法、能力图谱）的开发与优化，解决高并发、大数据量场景下的性能问题", "与前端、算法团队协作，完成业务需求的全流程落地，保障产品迭代效率"], "job_requirements": ["熟练掌握 Python 语言，有扎实的语法基础，熟悉 FastAPI 框架开发", "熟悉 MySQL 数据库，能独立完成 SQL 编写、索引优化与性能调优", "了解 NLP 或大模型应用开发，有简历解析、文本匹配相关项目经验优先"], "benefits": ["五险一金", "带薪年假", "年度体检", "节日福利", "弹性工作制", "定期技术分享会"], "company_intro": "未提供", "highlights": ["扁平化管理，技术氛围浓厚，支持个人技术成长与创新实践", "可参与核心项目架构设计，有机会接触前沿 AI 技术与国产化适配方案"]}', '["Python", "FastAPI", "MySQL", "SQLAlchemy", "RESTful API", "大模型应用开发", "Linux", "Git"]', '熟练掌握 Python 语言，有扎实的语法基础，熟悉 FastAPI 框架开发
